```java
public class MerryPrimeChecker {
    public static void main(String[] args) {
        int number = 7; // You can change this to any number you want to test!
        System.out.println("Is " + number + " a merry prime? " + isMerryPrime(number));
    }

    public static boolean isMerryPrime(int n) {
        if (!isPrime(n)) return false;
        return isHappy(n);
    }

    public static boolean isPrime(int n) {
        if (n <= 1) return false;
        if (n == 2) return true;
        if (n % 2 == 0) return false;
        for (int i = 3; i <= Math.sqrt(n); i += 2) {
            if (n % i == 0) return false;
        }
        return true;
    }

    public static boolean isHappy(int n) {
        int slow = n, fast = n;
        do {
            slow = sumOfSquares(slow);
            fast = sumOfSquares(sumOfSquares(fast));
        } while (slow != fast);
        return slow == 1;
    }

    public static int sumOfSquares(int n) {
        int sum = 0;
        while (n > 0) {
            int digit = n % 10;
            sum += digit * digit;
            n /= 10;
        }
        return sum;
    }
}
```

In this code:
- `isPrime(int n)` checks if the number is prime.
- `isHappy(int n)` checks if the number is a happy number.
- `isMerryPrime(int n)` checks if the number is both prime and happy.

