#include <iostream>
#include <unistd.h>
#include <sys/types.h>
#include <cstdio>

int main() {
    int pipeFD[2];  // A receptacle for the pipe's essence
    pid_t childPID; // The identifier for our new process, the offspring

    // Let's create the magical pipe!
    if (pipe(pipeFD) == -1) {
        perror("Pipe failed");
        return 1;
    }

    // Now, let's conjure the child process!
    childPID = fork();

    if (childPID < 0) { // If something went wrong with the fork
        perror("fork failed");
        return 1;
    } else if (childPID == 0) { // We're in the child process!
        // Close the unused end of the pipe (you can think of it as closing one end of a straw)
        close(pipeFD[1]);

        // Redirect our process's standard input and output to the pipe
        dup2(pipeFD[0], STDIN_FILENO);
        dup2(pipeFD[0], STDOUT_FILENO);

        // Execute a command, like a wizard casting a spell
        execlp("/bin/echo", "echo", "Hello, from the child process!", (char *)0);
    } else { // We're in the parent process!
        // Close the unused end of the pipe
        close(pipeFD[0]);

        // Write something to the pipe (like whispering a secret to the pipe)
        std::cout << "Hello, from the parent process!" << std::endl;
        std::cout.flush();

        // Read the response (like listening to the pipe for a reply)
        char buffer[100];
        read(pipeFD[1], buffer, sizeof(buffer));
        std::cout << "The child process replied: " << buffer << std::endl;
    }

    return 0;
}
